import{_ as t,o as r,c as o,a2 as n}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Streaming","description":"","frontmatter":{"title":"Streaming","status":"draft"},"headers":[],"relativePath":"research/concepts/streaming/index.md","filePath":"research/concepts/streaming/index.md"}'),a={name:"research/concepts/streaming/index.md"};function s(i,e,d,l,c,p){return r(),o("div",null,[...e[0]||(e[0]=[n(`<h1 id="streaming" tabindex="-1">Streaming <a class="header-anchor" href="#streaming" aria-label="Permalink to &quot;Streaming&quot;">​</a></h1><p>Streaming is the connective tissue of every coding agent — it bridges the gap between an LLM generating tokens at ~50-100 tok/s and a user expecting responsive, flicker-free output. This document traces the full path: <strong>protocol</strong> (how bytes arrive), <strong>parsing</strong> (how they become structured data), <strong>rendering</strong> (how users see them), and <strong>error recovery</strong> (what happens when things break).</p><hr><h2 id="protocols" tabindex="-1">Protocols <a class="header-anchor" href="#protocols" aria-label="Permalink to &quot;Protocols&quot;">​</a></h2><p>LLM API responses can take 5-60+ seconds to fully generate. Streaming protocols let agents begin processing tokens as they arrive rather than waiting for completion.</p><h3 id="server-sent-events-sse" tabindex="-1">Server-Sent Events (SSE) <a class="header-anchor" href="#server-sent-events-sse" aria-label="Permalink to &quot;Server-Sent Events (SSE)&quot;">​</a></h3><p>SSE is the <strong>dominant protocol</strong> across coding agents. Every major provider (OpenAI, Anthropic, Google, together.ai) supports it.</p><p><strong>How it works:</strong></p><ul><li>Client sends a standard HTTP POST with <code>Accept: text/event-stream</code></li><li>Server holds the connection open, sending newline-delimited events</li><li>Each event follows a simple text format: <code>data: {json}\\n\\n</code></li><li>The stream terminates with <code>data: [DONE]\\n\\n</code></li></ul><p><strong>Format example (OpenAI Chat Completions):</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>data: {&quot;id&quot;:&quot;chatcmpl-abc&quot;,&quot;choices&quot;:[{&quot;delta&quot;:{&quot;content&quot;:&quot;Hello&quot;}}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: {&quot;id&quot;:&quot;chatcmpl-abc&quot;,&quot;choices&quot;:[{&quot;delta&quot;:{&quot;content&quot;:&quot; world&quot;}}]}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>data: [DONE]</span></span></code></pre></div><p><strong>Why SSE dominates:</strong></p><ul><li>Works over standard HTTP/1.1 — no protocol upgrade needed</li><li>Unidirectional (server → client) matches the LLM streaming model perfectly</li><li>Firewalls and proxies handle it transparently</li><li>Built-in reconnection semantics via <code>Last-Event-ID</code></li><li>Every HTTP client library supports it</li></ul><p><strong>Limitations:</strong></p><ul><li>Unidirectional only — client cannot send data mid-stream (must open new request)</li><li>No binary framing — everything is UTF-8 text</li><li>No built-in backpressure — fast producers can overwhelm slow consumers</li><li>Connection limits per domain in browsers (6 per domain in HTTP/1.1)</li></ul><p><strong>Agents using SSE:</strong> OpenCode (via Go channels from provider SDKs), Claude Code (Anthropic Messages API), Gemini CLI (<code>client.ts</code> SSE handler), Codex (Responses API), Goose (via provider abstraction), Junie CLI (to JetBrains backend), Ante (cloud API calls).</p><h3 id="chunked-transfer-encoding" tabindex="-1">Chunked Transfer Encoding <a class="header-anchor" href="#chunked-transfer-encoding" aria-label="Permalink to &quot;Chunked Transfer Encoding&quot;">​</a></h3><p>The underlying HTTP mechanism that enables SSE. With <code>Transfer-Encoding: chunked</code>, the server sends response body in pieces without knowing the total content length upfront.</p><ul><li>SSE rides on top of chunked encoding — they are complementary, not alternatives</li><li>Some agents use raw chunked responses without SSE framing when talking to local models (e.g., Ollama&#39;s <code>/api/generate</code> endpoint returns newline-delimited JSON chunks)</li><li>Aider via litellm handles both SSE and raw chunked responses transparently depending on the provider</li></ul><h3 id="websockets" tabindex="-1">WebSockets <a class="header-anchor" href="#websockets" aria-label="Permalink to &quot;WebSockets&quot;">​</a></h3><p>Bidirectional communication over a single TCP connection. Used when agents need <strong>two-way streaming</strong> — sending and receiving simultaneously.</p><p><strong>When WebSockets make sense:</strong></p><ul><li><strong>Realtime conversation mode</strong> — Codex explicitly supports WebSocket for its realtime API (<code>supports_websockets</code> per-provider flag)</li><li><strong>IDE integration</strong> — OpenHands uses WebSocket as its primary server↔UI transport, with events flowing both directions through the <code>EventStream</code></li><li><strong>Persistent sessions</strong> — Droid&#39;s interface-agnostic protocol uses WebSocket for web/Slack/IDE frontends that need push notifications</li></ul><p><strong>Trade-offs vs SSE:</strong></p><table tabindex="0"><thead><tr><th>Aspect</th><th>SSE</th><th>WebSocket</th></tr></thead><tbody><tr><td>Direction</td><td>Server → Client</td><td>Bidirectional</td></tr><tr><td>Protocol</td><td>HTTP/1.1</td><td>Upgrade from HTTP</td></tr><tr><td>Reconnection</td><td>Built-in</td><td>Manual</td></tr><tr><td>Proxy support</td><td>Excellent</td><td>Sometimes problematic</td></tr><tr><td>Overhead</td><td>Minimal (text)</td><td>Minimal (binary frames)</td></tr><tr><td>Use case</td><td>LLM token streaming</td><td>Realtime/interactive</td></tr></tbody></table><p>Most agents use SSE for LLM streaming and reserve WebSockets for UI transport when a web frontend or IDE plugin needs bidirectional communication.</p><h3 id="openai-responses-api-streaming" tabindex="-1">OpenAI Responses API Streaming <a class="header-anchor" href="#openai-responses-api-streaming" aria-label="Permalink to &quot;OpenAI Responses API Streaming&quot;">​</a></h3><p>Codex CLI is the clearest example of OpenAI&#39;s newer <strong>Responses API</strong> (<code>/v1/responses</code>), which replaces Chat Completions with a richer event model:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>ResponseCreated { id }</span></span>
<span class="line"><span>ItemCreated(ResponseItem)      // new content item started</span></span>
<span class="line"><span>ItemUpdated(ResponseItem)      // delta within an item</span></span>
<span class="line"><span>ItemCompleted(ResponseItem)    // item finalized</span></span>
<span class="line"><span>ResponseCompleted { usage }    // stream done</span></span>
<span class="line"><span>Error { message }              // stream error</span></span></code></pre></div><p>Key differences from Chat Completions streaming:</p><ul><li><strong>Item-level granularity</strong> — responses contain multiple typed items (<code>Message</code>, <code>LocalShellCall</code>, <code>FunctionCall</code>, <code>Reasoning</code>, <code>WebSearchCall</code>) rather than a flat <code>choices[].delta</code></li><li><strong>Built-in tool call lifecycle</strong> — tool calls have explicit created/updated/completed events</li><li><strong>Native reasoning tokens</strong> — <code>Reasoning</code> items stream extended thinking separately</li><li>Codex fully committed to this API, dropping Chat Completions entirely</li></ul><h3 id="protocol-selection-guide" tabindex="-1">Protocol Selection Guide <a class="header-anchor" href="#protocol-selection-guide" aria-label="Permalink to &quot;Protocol Selection Guide&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Scenario</th><th>Best Protocol</th><th>Example</th></tr></thead><tbody><tr><td>Standard LLM token streaming</td><td>SSE</td><td>Most agents</td></tr><tr><td>Local model (Ollama, llama.cpp)</td><td>Chunked JSON lines</td><td>Aider, OpenCode</td></tr><tr><td>Bidirectional realtime</td><td>WebSocket</td><td>Codex realtime mode</td></tr><tr><td>Web UI ↔ backend</td><td>WebSocket</td><td>OpenHands, Droid</td></tr><tr><td>IDE plugin ↔ agent</td><td>WebSocket or stdio</td><td>Junie, Droid</td></tr><tr><td>MCP server transport</td><td>stdio or SSE</td><td>Ante, Codex, Goose</td></tr></tbody></table><hr><h2 id="parsing" tabindex="-1">Parsing <a class="header-anchor" href="#parsing" aria-label="Permalink to &quot;Parsing&quot;">​</a></h2><p>Raw stream chunks must be assembled into structured data — text content, tool calls, thinking tokens. This is harder than it sounds because chunks arrive at arbitrary boundaries.</p><h3 id="delta-vs-snapshot-streaming-models" tabindex="-1">Delta vs Snapshot Streaming Models <a class="header-anchor" href="#delta-vs-snapshot-streaming-models" aria-label="Permalink to &quot;Delta vs Snapshot Streaming Models&quot;">​</a></h3><p>The two major providers use fundamentally different streaming approaches:</p><p><strong>OpenAI — Delta model:</strong></p><ul><li>Each chunk contains only the <strong>change</strong> from the previous state</li><li><code>choices[0].delta.content</code> = new text to append</li><li>Tool calls arrive as <code>tool_calls[i].function.arguments</code> delta strings — partial JSON fragments</li><li>Agent must maintain running state and apply deltas incrementally</li></ul><p><strong>Anthropic — Content block model:</strong></p><ul><li>Events structured around content blocks: <code>content_block_start</code>, <code>content_block_delta</code>, <code>content_block_stop</code></li><li>Each block has a type (<code>text</code>, <code>tool_use</code>, <code>thinking</code>) and an index</li><li>Deltas arrive within block context, making it clear what they belong to</li><li><code>message_start</code> → <code>content_block_start</code> → N × <code>content_block_delta</code> → <code>content_block_stop</code> → <code>message_stop</code></li></ul><p><strong>OpenAI Responses API — Item model (Codex):</strong></p><ul><li><code>ItemCreated</code> → N × <code>ItemUpdated</code> → <code>ItemCompleted</code></li><li>Each item is typed (<code>Message</code>, <code>FunctionCall</code>, <code>LocalShellCall</code>, <code>Reasoning</code>)</li><li>Richer lifecycle than Chat Completions deltas</li></ul><p><strong>How agents normalize these differences:</strong></p><table tabindex="0"><thead><tr><th>Agent</th><th>Strategy</th></tr></thead><tbody><tr><td><strong>OpenCode</strong></td><td>Provider layer emits unified <code>ProviderEvent</code> types (<code>EventContentDelta</code>, <code>EventToolUseStart</code>, etc.) regardless of upstream provider</td></tr><tr><td><strong>Aider</strong></td><td>litellm normalizes across providers; Coder subclass parses the edit format from the final response</td></tr><tr><td><strong>Goose</strong></td><td><code>stream_response_from_provider()</code> yields <code>(Option&lt;Message&gt;, Option&lt;ProviderUsage&gt;)</code> pairs — provider differences hidden</td></tr><tr><td><strong>Codex</strong></td><td>Only supports Responses API — no normalization needed</td></tr><tr><td><strong>Gemini CLI</strong></td><td><code>contentGenerator.ts</code> bridges agent loop and LLM client, normalizing Gemini&#39;s response format</td></tr></tbody></table><h3 id="incremental-json-parsing" tabindex="-1">Incremental JSON Parsing <a class="header-anchor" href="#incremental-json-parsing" aria-label="Permalink to &quot;Incremental JSON Parsing&quot;">​</a></h3><p>Tool call arguments arrive as partial JSON strings across multiple chunks. A typical sequence:</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>Chunk 1: {&quot;function&quot;: {&quot;arguments&quot;: &quot;{\\&quot;path\\&quot;: \\&quot;/sr&quot;}}</span></span>
<span class="line"><span>Chunk 2: {&quot;function&quot;: {&quot;arguments&quot;: &quot;c/main.rs\\&quot;, \\&quot;co&quot;}}</span></span>
<span class="line"><span>Chunk 3: {&quot;function&quot;: {&quot;arguments&quot;: &quot;ntent\\&quot;: \\&quot;fn main()\\&quot;}&quot;}}</span></span></code></pre></div><p>The agent must concatenate argument fragments and parse only when complete. Strategies:</p><ol><li><p><strong>String accumulation</strong> (most common): Buffer argument string fragments, attempt <code>JSON.parse()</code> / <code>serde_json::from_str()</code> only after <code>ItemCompleted</code> or <code>content_block_stop</code>. Used by OpenCode, Goose, Codex.</p></li><li><p><strong>Streaming JSON parser</strong>: Libraries like <code>ijson</code> (Python) or <code>serde_json::StreamDeserializer</code> (Rust) can parse incrementally. Rarely used in practice because tool call JSON is small enough that buffering is simpler.</p></li><li><p><strong>Argument coercion</strong>: Even after successful parsing, the JSON may not match the schema. Goose runs a coercion pass — converting <code>&quot;42&quot;</code> (string) to <code>42</code> (number) when the schema expects an integer — to handle common LLM mistakes.</p></li></ol><h3 id="partial-tool-call-assembly" tabindex="-1">Partial Tool Call Assembly <a class="header-anchor" href="#partial-tool-call-assembly" aria-label="Permalink to &quot;Partial Tool Call Assembly&quot;">​</a></h3><p>Tool calls are the most complex streaming artifact to assemble. The lifecycle varies by provider:</p><p><strong>OpenCode&#39;s approach (Go channels):</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>EventToolUseStart  →  creates new tool call entry on message</span></span>
<span class="line"><span>  (stream continues with content deltas)</span></span>
<span class="line"><span>EventToolUseStop   →  finalizes tool call by ID</span></span>
<span class="line"><span>EventComplete      →  reconciles with SetToolCalls() as final truth</span></span></code></pre></div><p>Each event immediately persists to SQLite and publishes via pub/sub — the TUI sees tool calls materialize in real time.</p><p><strong>Codex&#39;s approach (Responses API items):</strong></p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span>ItemCreated(FunctionCall)   →  tool call shell created</span></span>
<span class="line"><span>ItemUpdated(FunctionCall)   →  arguments accumulating</span></span>
<span class="line"><span>ItemCompleted(FunctionCall) →  ready for execution</span></span></code></pre></div><p>The <code>ToolRouter.build_tool_call()</code> maps completed items to executable <code>ToolCall</code> structs, routing to MCP servers, built-in handlers, or the local shell.</p><p><strong>Goose&#39;s approach (categorized dispatch):</strong> After the stream completes, <code>categorize_tools()</code> splits tool requests into <strong>frontend tools</strong> (executed in the UI) and <strong>remaining tools</strong> (executed server-side). This two-tier routing enables UI-specific tools like confirmation dialogs.</p><h3 id="thinking-reasoning-tokens" tabindex="-1">Thinking / Reasoning Tokens <a class="header-anchor" href="#thinking-reasoning-tokens" aria-label="Permalink to &quot;Thinking / Reasoning Tokens&quot;">​</a></h3><p>Extended thinking (Claude) and chain-of-thought (o1/o3) introduce a separate token stream:</p><ul><li><strong>Anthropic</strong>: <code>thinking</code> content blocks with their own <code>content_block_start/delta/stop</code> lifecycle. Claude Code toggles visibility with <code>Ctrl+O</code>.</li><li><strong>OpenAI Responses API</strong>: <code>Reasoning</code> items in the response. Codex surfaces these via <code>EQ::Reasoning</code> events.</li><li><strong>OpenCode</strong>: <code>EventThinkingDelta</code> events append to <code>ReasoningContent</code> on the message, published via the same pub/sub path as regular content.</li><li><strong>Aider</strong>: Detects reasoning-capable models in <code>models.py</code> and routes them to <code>ArchitectCoder</code> (two-model pipeline) where the reasoning model plans and a faster model edits.</li></ul><p>Thinking tokens are typically <strong>not billed</strong> in the same way but consume streaming time — agents must decide whether to display them (adds latency to perceived responsiveness) or hide them (user wonders why there&#39;s a pause).</p><h3 id="error-handling-during-parsing" tabindex="-1">Error Handling During Parsing <a class="header-anchor" href="#error-handling-during-parsing" aria-label="Permalink to &quot;Error Handling During Parsing&quot;">​</a></h3><p>Malformed chunks and interrupted streams are common in production:</p><ul><li><strong>Truncated JSON</strong>: If the stream terminates mid-argument, the accumulated partial JSON is discarded. OpenCode finalizes the message with <code>FinishReasonCanceled</code>.</li><li><strong>Invalid UTF-8</strong>: SSE is text-only; binary artifacts in responses (rare) cause parse failures. Agents typically skip the offending chunk.</li><li><strong>Out-of-order events</strong>: The item model (Responses API) can theoretically deliver <code>ItemUpdated</code> before <code>ItemCreated</code> during network reordering. Codex handles this by buffering updates for unknown item IDs.</li><li><strong>Provider-specific quirks</strong>: Gemini sometimes produces tool calls in non-standard formats. Aider&#39;s model-specific edit format routing (<code>Gemini → diff-fenced</code>) works around provider-specific parsing issues.</li></ul><hr><h2 id="rendering" tabindex="-1">Rendering <a class="header-anchor" href="#rendering" aria-label="Permalink to &quot;Rendering&quot;">​</a></h2><p>Parsing produces structured data; rendering turns it into something a human can follow in real time. This is where agents diverge most dramatically — from 350-line scripts with raw <code>print()</code> to GPU-accelerated rendering pipelines.</p><h3 id="token-by-token-display" tabindex="-1">Token-by-Token Display <a class="header-anchor" href="#token-by-token-display" aria-label="Permalink to &quot;Token-by-Token Display&quot;">​</a></h3><p>The simplest approach: print each token as it arrives.</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#CDD6F4;"> chunk </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> stream</span><span style="color:#9399B2;">:</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">    print</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">chunk</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">content</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> end</span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;">&quot;&quot;</span><span style="color:#9399B2;">,</span><span style="color:#EBA0AC;font-style:italic;"> flush</span><span style="color:#94E2D5;">=</span><span style="color:#CBA6F7;">True</span><span style="color:#9399B2;">)</span></span></code></pre></div><p><strong>Who uses it:</strong> mini-SWE-agent (~350 lines total, no TUI), simple scripts, headless/CI modes.</p><p><strong>Problems:</strong></p><ul><li>Terminal flicker on fast token arrival</li><li>Markdown formatting impossible mid-stream (you can&#39;t render <code>**bold**</code> until you&#39;ve seen the closing <code>**</code>)</li><li>No place for status indicators, progress bars, or permission dialogs</li><li>Interleaved output if multiple streams are active</li></ul><h3 id="buffered-rendering" tabindex="-1">Buffered Rendering <a class="header-anchor" href="#buffered-rendering" aria-label="Permalink to &quot;Buffered Rendering&quot;">​</a></h3><p>Accumulate tokens, then render at intervals or on semantic boundaries (sentence end, newline, code fence).</p><ul><li><strong>Pi Coding Agent</strong>: Explicit <strong>differential rendering</strong> — only re-renders changed portions of the screen. &quot;Critical for a coding agent where LLM responses stream in token-by-token.&quot; Retains a component tree and triggers targeted re-renders.</li><li><strong>Aider</strong>: Processes full responses rather than token-by-token display. The edit format parser operates on complete output, rendering diffs after full content is available.</li><li><strong>Gemini CLI headless mode</strong>: Buffers output and emits in three formats — <code>text</code> (human-readable), <code>JSON</code> (structured), <code>stream-json</code> (newline-delimited JSON events).</li></ul><h3 id="tui-frameworks" tabindex="-1">TUI Frameworks <a class="header-anchor" href="#tui-frameworks" aria-label="Permalink to &quot;TUI Frameworks&quot;">​</a></h3><p>Most production agents use a TUI framework for structured terminal rendering:</p><h4 id="ink-react-for-cli-—-claude-code-gemini-cli" tabindex="-1">Ink (React for CLI) — Claude Code, Gemini CLI <a class="header-anchor" href="#ink-react-for-cli-—-claude-code-gemini-cli" aria-label="Permalink to &quot;Ink (React for CLI) — Claude Code, Gemini CLI&quot;">​</a></h4><p>Ink brings React&#39;s component model to the terminal. The entire CLI is a React component tree rendered to ANSI output.</p><ul><li><strong>Architecture</strong>: JSX/TSX components handle input, diff rendering, spinners, permission dialogs</li><li><strong>Reactive updates</strong>: State changes trigger re-renders (React reconciliation against terminal output)</li><li><strong>Keyboard handling</strong>: Component-level event handlers (<code>Esc</code> = interrupt, <code>Shift+Tab</code> = cycle modes)</li><li><strong>Rich components</strong>: Inline diffs, progress bars (native iTerm2/Windows Terminal protocols), code blocks</li><li><strong>Strengths</strong>: Familiar React mental model; composable; handles layout, state, and input elegantly</li><li><strong>Weaknesses</strong>: Node.js dependency; React reconciliation overhead; limited to what React can express</li></ul><p>Gemini CLI uses the same framework, with <code>packages/cli/src/ui/</code> containing Ink components and a separate <code>packages/core/</code> that remains UI-agnostic.</p><h4 id="bubble-tea-go-—-opencode" tabindex="-1">Bubble Tea (Go) — OpenCode <a class="header-anchor" href="#bubble-tea-go-—-opencode" aria-label="Permalink to &quot;Bubble Tea (Go) — OpenCode&quot;">​</a></h4><p>Bubble Tea follows The Elm Architecture: <code>Model</code> (state) → <code>Update</code> (message handler) → <code>View</code> (renderer).</p><ul><li><strong>Architecture</strong>: <code>internal/tui/components/</code> (reusable widgets), <code>internal/tui/page/</code> (chat, logs), <code>internal/tui/layout/</code></li><li><strong>Styling</strong>: Lip Gloss for declarative style definitions</li><li><strong>Streaming integration</strong>: Services publish events via a generic typed <code>Broker[T]</code> pub/sub system. Every streaming delta hits SQLite, triggers pub/sub, and reaches the TUI as a Bubble Tea message.</li><li><strong>Themes</strong>: Catppuccin and others via <code>internal/tui/theme/</code></li><li><strong>Image rendering</strong>: <code>internal/tui/image/</code> for inline terminal images</li><li><strong>Strengths</strong>: Single binary (Go); Elm Architecture keeps state management clean; fast startup</li><li><strong>Weaknesses</strong>: Less composable than React; custom layout logic needed; smaller ecosystem than Ink</li></ul><h4 id="ratatui-rust-—-codex-cli" tabindex="-1">Ratatui (Rust) — Codex CLI <a class="header-anchor" href="#ratatui-rust-—-codex-cli" aria-label="Permalink to &quot;Ratatui (Rust) — Codex CLI&quot;">​</a></h4><p>Ratatui is a Rust TUI library providing immediate-mode rendering with widgets.</p><ul><li><strong>Architecture</strong>: <code>codex-rs/tui/</code> consumes <code>EventMsg</code> from the Event Queue (EQ)</li><li><strong>SQ/EQ separation</strong>: TUI is just one frontend — the same EQ events power exec mode (JSONL output), app-server (IDE), and MCP server</li><li><strong>Non-interactive mode</strong>: <code>codex-rs/exec/</code> is a simpler event processor supporting human-readable, JSONL, and ephemeral output</li><li><strong>Strengths</strong>: Zero-cost abstractions; memory safety; same binary as the agent core</li><li><strong>Weaknesses</strong>: Steeper learning curve; less mature ecosystem than Ink</li></ul><h4 id="rust-metal-gpu-—-warp" tabindex="-1">Rust + Metal GPU — Warp <a class="header-anchor" href="#rust-metal-gpu-—-warp" aria-label="Permalink to &quot;Rust + Metal GPU — Warp&quot;">​</a></h4><p>Warp takes a fundamentally different approach: <strong>GPU-accelerated rendering</strong> via Metal shaders.</p><p><strong>Pipeline:</strong> Rust Application Logic → Element Tree (Flutter-inspired) → GPU Primitives (<code>rect</code>, <code>image</code>, <code>glyph</code>) → Metal Shaders (~250 lines MSL) → Screen Output</p><p><strong>Why GPU rendering for a terminal?</strong></p><ul><li><strong>Performance</strong>: 400+ fps, ~1.9ms average redraw — enables smooth animations, transitions, and rich UI elements</li><li><strong>Rich UI elements impossible in text-grid terminals</strong>: Inline accept/reject buttons, syntax-highlighted diff views with rich color, smooth progress bar animations, inline images, multi-font rendering</li><li><strong>Agent conversation view</strong>: Dedicated workspace with plans, diffs, task tracking — layouts that exceed what character-cell terminals can express</li><li><strong>Block-based model</strong>: Each command+output is a discrete Block with its own grid (forked from Alacritty), enabling per-block scrolling, independent rendering, and metadata overlays</li></ul><p>The framework was co-developed with Nathan Sobo (Atom/Zed co-founder), using a Flutter-inspired widget model with declarative element tree and flexbox-inspired layout.</p><h4 id="raw-ansi-minimal-rendering" tabindex="-1">Raw ANSI / Minimal Rendering <a class="header-anchor" href="#raw-ansi-minimal-rendering" aria-label="Permalink to &quot;Raw ANSI / Minimal Rendering&quot;">​</a></h4><p>Agents targeting simplicity or CI/headless environments skip TUI frameworks entirely:</p><ul><li><strong>mini-SWE-agent</strong>: Raw <code>subprocess.run</code> with <code>stdout=subprocess.PIPE</code>. No streaming, no progress indicators. Completion detected via magic string sentinel.</li><li><strong>ForgeCode</strong>: ZSH-native integration with <code>:</code> prefix commands. No custom TUI — uses the shell itself.</li><li><strong>Aider</strong>: <code>prompt_toolkit</code> for rich terminal interaction — syntax highlighting, tab completion, color-coded output — but not a full TUI framework.</li></ul><h4 id="framework-comparison" tabindex="-1">Framework Comparison <a class="header-anchor" href="#framework-comparison" aria-label="Permalink to &quot;Framework Comparison&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Framework</th><th>Language</th><th>Architecture</th><th>Streaming Model</th><th>Rich UI</th><th>Complexity</th></tr></thead><tbody><tr><td><strong>Ink</strong></td><td>TypeScript</td><td>React component tree</td><td>State → re-render</td><td>High (components)</td><td>Medium</td></tr><tr><td><strong>Bubble Tea</strong></td><td>Go</td><td>Elm Architecture</td><td>Pub/sub → messages</td><td>Medium</td><td>Medium</td></tr><tr><td><strong>Ratatui</strong></td><td>Rust</td><td>Immediate-mode widgets</td><td>EQ events → draw</td><td>Medium</td><td>Medium-High</td></tr><tr><td><strong>Metal GPU</strong></td><td>Rust</td><td>Flutter widget tree</td><td>Element tree → GPU</td><td>Very High</td><td>Very High</td></tr><tr><td><strong>pi-tui</strong></td><td>TypeScript</td><td>Custom retained-mode</td><td>Differential render</td><td>High</td><td>High (custom)</td></tr><tr><td><strong>prompt_toolkit</strong></td><td>Python</td><td>Input/output library</td><td>Full response</td><td>Low-Medium</td><td>Low</td></tr><tr><td><strong>Raw ANSI</strong></td><td>Any</td><td>print()</td><td>Token-by-token</td><td>Minimal</td><td>Minimal</td></tr></tbody></table><h3 id="markdown-rendering" tabindex="-1">Markdown Rendering <a class="header-anchor" href="#markdown-rendering" aria-label="Permalink to &quot;Markdown Rendering&quot;">​</a></h3><p>LLM output is typically markdown — code fences, headers, bold, lists. Rendering this live during streaming is a challenge because markdown is context-dependent (you need the closing \`\`\` to know a code block ended).</p><p><strong>Approaches:</strong></p><ul><li><strong>Ink/React agents</strong> (Claude Code, Gemini CLI): Markdown→component pipeline renders formatted output. Code blocks get syntax highlighting, diffs render as colored inline components.</li><li><strong>Aider</strong>: Full markdown rendering via <code>io.py</code> after response completion — syntax-highlighted code display with color-coded sections (user input, AI output, tool output, errors).</li><li><strong>OpenCode</strong>: Lip Gloss styles applied to rendered markdown content in the Bubble Tea view.</li><li><strong>Warp</strong>: GPU-rendered markdown with full syntax highlighting, multi-font support, and rich diff views.</li><li><strong>Headless modes</strong>: Strip markdown to plain text (Gemini CLI <code>text</code> format) or preserve as structured data (<code>JSON</code>, <code>stream-json</code>).</li></ul><h3 id="progress-indicators" tabindex="-1">Progress Indicators <a class="header-anchor" href="#progress-indicators" aria-label="Permalink to &quot;Progress Indicators&quot;">​</a></h3><p>During tool execution (which can take seconds to minutes), agents need to signal activity:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Approach</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td>Customizable spinner verbs (<code>spinnerVerbs</code> setting); native progress bar protocols for iTerm2/Windows Terminal</td></tr><tr><td><strong>OpenCode</strong></td><td>Spinner and formatting utilities in <code>internal/format/</code>; pub/sub events drive status updates</td></tr><tr><td><strong>Codex</strong></td><td>Turn lifecycle events: <code>TurnStarted</code> → <code>ExecApprovalRequest</code> → <code>TurnComplete</code> displayed in TUI</td></tr><tr><td><strong>Warp</strong></td><td>GPU-rendered smooth animated progress bars; inline action buttons; Active AI overlay</td></tr><tr><td><strong>Junie</strong></td><td>Emoji status indicators: ✅ ✏️ ➕ ⏭️ ❌ in plan presentation</td></tr><tr><td><strong>Pi</strong></td><td>Event streaming (<code>tool:start</code>, <code>tool:complete</code>) drives TUI status lines; extensions add custom indicators</td></tr><tr><td><strong>Droid</strong></td><td>OpenTelemetry-based metrics; progress updates across any interface (Slack, web, CLI)</td></tr></tbody></table><hr><h2 id="error-recovery" tabindex="-1">Error Recovery <a class="header-anchor" href="#error-recovery" aria-label="Permalink to &quot;Error Recovery&quot;">​</a></h2><p>Streams break. Networks drop. Rate limits hit mid-generation. Robust agents handle all of this gracefully.</p><h3 id="reconnection-strategies" tabindex="-1">Reconnection Strategies <a class="header-anchor" href="#reconnection-strategies" aria-label="Permalink to &quot;Reconnection Strategies&quot;">​</a></h3><p>SSE has built-in reconnection via <code>Last-Event-ID</code>, but most LLM APIs don&#39;t support resuming a generation mid-stream. In practice, agents treat a dropped stream as a failed turn:</p><ul><li><strong>Codex</strong>: <code>stream_max_retries = 5</code> with <code>stream_idle_timeout_ms = 300,000</code> (5 min). If the stream goes idle or drops, retry the entire request up to 5 times.</li><li><strong>OpenCode</strong>: <code>maxRetries = 8</code> at the provider layer. Failed streams finalize the message with <code>FinishReasonCanceled</code> and surface the error.</li><li><strong>Gemini CLI</strong>: Retry logic in <code>baseLlmClient.ts</code> with a dedicated <code>fallback/</code> module for routing to alternative models when the primary is unavailable.</li></ul><h3 id="retry-with-backoff" tabindex="-1">Retry with Backoff <a class="header-anchor" href="#retry-with-backoff" aria-label="Permalink to &quot;Retry with Backoff&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Agent</th><th>Max Retries</th><th>Backoff Strategy</th><th>Timeout</th></tr></thead><tbody><tr><td><strong>Codex</strong></td><td>5 (stream) / 4 (request)</td><td>Provider-configured</td><td>300s idle timeout</td></tr><tr><td><strong>OpenCode</strong></td><td>8</td><td>Provider layer</td><td>Context-based cancellation</td></tr><tr><td><strong>Goose</strong></td><td>2 (compaction attempts)</td><td>Immediate retry</td><td>1000 turns max</td></tr><tr><td><strong>ForgeCode</strong></td><td><code>max_tool_failure_per_turn</code></td><td>Configurable</td><td><code>FORGE_TOOL_TIMEOUT</code> = 300s</td></tr><tr><td><strong>Gemini CLI</strong></td><td>Configurable</td><td>Fallback module</td><td>Turn iteration limits</td></tr></tbody></table><h3 id="partial-response-recovery" tabindex="-1">Partial Response Recovery <a class="header-anchor" href="#partial-response-recovery" aria-label="Permalink to &quot;Partial Response Recovery&quot;">​</a></h3><p>When a stream terminates mid-generation, agents must decide what to do with the partial content:</p><ol><li><p><strong>Discard and retry</strong> (most common): The incomplete response is discarded, and the request is retried from scratch. OpenCode, Codex, and Gemini CLI all take this approach.</p></li><li><p><strong>Preserve partial content</strong>: Some agents save the partial response for debugging or user inspection. OpenCode persists every delta to SQLite — even if the stream fails, the partial message is in the database.</p></li><li><p><strong>Emergency compaction</strong>: Goose handles <code>ContextLengthExceeded</code> mid-stream by triggering <code>compact_messages()</code>, replacing the conversation with a summary, and retrying. Up to 2 compaction attempts before giving up.</p></li><li><p><strong>Checkpoint-based recovery</strong>: Claude Code takes file snapshots before every edit. If a stream fails during a multi-tool turn, the user can rewind to any previous state via <code>Esc + Esc</code>. This isn&#39;t stream-level recovery but turn-level — the granularity that matters to users.</p></li></ol><h3 id="handling-rate-limits-mid-stream" tabindex="-1">Handling Rate Limits Mid-Stream <a class="header-anchor" href="#handling-rate-limits-mid-stream" aria-label="Permalink to &quot;Handling Rate Limits Mid-Stream&quot;">​</a></h3><p>Rate limits can hit before streaming starts (HTTP 429) or during streaming (connection terminated):</p><ul><li><strong>Goose</strong>: <code>CreditsExhausted</code> yields a notification with <code>top_up_url</code> and breaks the loop cleanly</li><li><strong>Codex</strong>: Provider-level retry handles 429s; <code>stream_max_retries</code> covers mid-stream termination</li><li><strong>Aider</strong>: litellm handles rate limiting and retries transparently across providers</li><li><strong>Gemini CLI</strong>: Routing module with fallback handling when primary model is rate-limited</li></ul><h3 id="network-interruption-graceful-degradation" tabindex="-1">Network Interruption Graceful Degradation <a class="header-anchor" href="#network-interruption-graceful-degradation" aria-label="Permalink to &quot;Network Interruption Graceful Degradation&quot;">​</a></h3><p>When the network fails entirely:</p><ul><li><strong>Goose</strong>: Yields &quot;please resend your last message&quot; and breaks — preserving conversation state for when connectivity returns</li><li><strong>OpenCode</strong>: Context-based cancellation at 4 levels (session, loop, stream, tool). When cancelled mid-stream, the message is finalized using <code>context.Background()</code> to ensure the DB write succeeds even though the parent context is cancelled.</li><li><strong>Codex</strong>: <code>Op::Interrupt</code> cancels active streams, aborts pending tools, emits <code>TurnAborted</code> — clean state for retry</li><li><strong>OpenHands</strong>: The entire event stream is persistent and append-only. <code>ReplayManager</code> can reconstruct state from any point. Network failures lose nothing.</li><li><strong>Ante</strong>: Lock-free scheduler ensures no sub-agent blocks another — if one sub-agent&#39;s stream fails, others continue unaffected</li></ul><h3 id="user-initiated-interruption" tabindex="-1">User-Initiated Interruption <a class="header-anchor" href="#user-initiated-interruption" aria-label="Permalink to &quot;User-Initiated Interruption&quot;">​</a></h3><p>Users pressing <code>Ctrl+C</code> or <code>Esc</code> mid-stream is the most common &quot;error&quot; case:</p><table tabindex="0"><thead><tr><th>Agent</th><th>Interrupt Mechanism</th><th>State After</th></tr></thead><tbody><tr><td><strong>Claude Code</strong></td><td><code>Esc</code> (context preserved)</td><td>Can continue conversation</td></tr><tr><td><strong>OpenCode</strong></td><td>Context cancellation cascade</td><td>Message finalized as canceled</td></tr><tr><td><strong>Codex</strong></td><td><code>Op::Interrupt</code> via SQ</td><td><code>TurnAborted</code> event, clean state</td></tr><tr><td><strong>Goose</strong></td><td><code>CancellationToken</code> checked per iteration</td><td>Loop exits cleanly</td></tr><tr><td><strong>Pi</strong></td><td><code>Enter</code> = steering message; <code>Alt+Enter</code> = queued follow-up</td><td>Conversation continues with injection</td></tr></tbody></table><p>Pi&#39;s approach is notable: rather than canceling, the user can <strong>steer</strong> the agent mid-stream by pressing Enter to inject a message after the current tool call but before the next LLM inference.</p><hr><h2 id="tools-projects" tabindex="-1">Tools &amp; Projects <a class="header-anchor" href="#tools-projects" aria-label="Permalink to &quot;Tools &amp; Projects&quot;">​</a></h2><p>Key open-source tools and libraries for building streaming UIs in coding agents, organized by category.</p><h3 id="tui-frameworks-1" tabindex="-1">TUI Frameworks <a class="header-anchor" href="#tui-frameworks-1" aria-label="Permalink to &quot;TUI Frameworks&quot;">​</a></h3><p>Frameworks for building interactive terminal user interfaces that render streaming LLM output.</p><table tabindex="0"><thead><tr><th>Framework</th><th>Language</th><th>Architecture</th><th>URL</th><th>Why It Matters for Streaming</th></tr></thead><tbody><tr><td><strong>Ink</strong></td><td>TypeScript</td><td>React (declarative)</td><td><a href="https://github.com/vadimdemedes/ink" target="_blank" rel="noreferrer">github.com/vadimdemedes/ink</a></td><td>React reconciliation diffs efficiently on each token; <code>&lt;Static&gt;</code> freezes finalized output above live content. Used by Claude Code, Gemini CLI, Copilot CLI.</td></tr><tr><td><strong>Bubble Tea</strong></td><td>Go</td><td>Elm Architecture (TEA)</td><td><a href="https://github.com/charmbracelet/bubbletea" target="_blank" rel="noreferrer">github.com/charmbracelet/bubbletea</a></td><td>Message-passing maps naturally to SSE chunks — each chunk dispatched as a <code>tea.Msg</code>. Used by OpenCode. Ecosystem: Bubbles (components), Lip Gloss (styling), Glamour (markdown).</td></tr><tr><td><strong>Ratatui</strong></td><td>Rust</td><td>Immediate-mode</td><td><a href="https://github.com/ratatui/ratatui" target="_blank" rel="noreferrer">github.com/ratatui/ratatui</a></td><td>Redraws full state each frame — no diffing needed. Pair with tokio channels for streaming chunk ingestion. Used by Codex CLI.</td></tr><tr><td><strong>Textual</strong></td><td>Python</td><td>Component + CSS (async)</td><td><a href="https://github.com/Textualize/textual" target="_blank" rel="noreferrer">github.com/Textualize/textual</a></td><td>Async-first (asyncio) integrates directly with async LLM streaming APIs. CSS theming for consistent styling.</td></tr><tr><td><strong>Rich</strong></td><td>Python</td><td>Renderable library</td><td><a href="https://github.com/Textualize/rich" target="_blank" rel="noreferrer">github.com/Textualize/rich</a></td><td><code>Live</code> display for real-time updates, <code>Markdown</code> renderable for incremental rendering, <code>Progress</code> for multi-step workflows. Not a full TUI — pair with Textual for interactivity.</td></tr></tbody></table><h3 id="llm-streaming-libraries" tabindex="-1">LLM Streaming Libraries <a class="header-anchor" href="#llm-streaming-libraries" aria-label="Permalink to &quot;LLM Streaming Libraries&quot;">​</a></h3><p>SDKs that handle HTTP connections to LLM APIs and normalize streaming across providers.</p><ul><li><strong>LiteLLM</strong> — Unified Python API calling 100+ LLMs in OpenAI-compatible format. Normalizes streaming across all providers with <code>stream=True</code>. <a href="https://github.com/BerriAI/litellm" target="_blank" rel="noreferrer">github.com/BerriAI/litellm</a>. Essential for multi-provider coding agents — write one streaming handler for any model.</li><li><strong>Vercel AI SDK</strong> — Provider-agnostic TypeScript toolkit with <code>streamText()</code> and <code>streamObject()</code> primitives. <a href="https://github.com/vercel/ai" target="_blank" rel="noreferrer">github.com/vercel/ai</a>. Unified streaming across OpenAI, Anthropic, Google with UI hooks like <code>useChat</code>. The most feature-rich TS option.</li><li><strong>OpenAI Python/Node SDKs</strong> — Official clients with SSE-based streaming via <code>stream=True</code>. Support both Chat Completions and Responses API. <a href="https://github.com/openai/openai-python" target="_blank" rel="noreferrer">openai-python</a> / <a href="https://github.com/openai/openai-node" target="_blank" rel="noreferrer">openai-node</a>. Reference implementations that most agents build on.</li><li><strong>Anthropic Python SDK</strong> — Official Claude SDK with content-block event streaming and extended thinking support. <a href="https://github.com/anthropics/anthropic-sdk-python" target="_blank" rel="noreferrer">github.com/anthropics/anthropic-sdk-python</a>. Mirrors Anthropic&#39;s unique content-block-based protocol.</li></ul><table tabindex="0"><thead><tr><th>SDK</th><th>Language</th><th>Providers</th><th>Abstraction Level</th></tr></thead><tbody><tr><td><strong>LiteLLM</strong></td><td>Python</td><td>100+ (all major)</td><td>Highest — normalizes to OpenAI format</td></tr><tr><td><strong>Vercel AI SDK</strong></td><td>TypeScript</td><td>All major</td><td>High — unified stream primitives</td></tr><tr><td><strong>OpenAI SDK</strong></td><td>Python / TS</td><td>OpenAI only</td><td>Low — provider-specific</td></tr><tr><td><strong>Anthropic SDK</strong></td><td>Python / TS</td><td>Anthropic only</td><td>Low — provider-specific</td></tr></tbody></table><h3 id="sse-transport-libraries" tabindex="-1">SSE &amp; Transport Libraries <a class="header-anchor" href="#sse-transport-libraries" aria-label="Permalink to &quot;SSE &amp; Transport Libraries&quot;">​</a></h3><p>SSE (Server-Sent Events) is the dominant transport for LLM streaming. These libraries handle the low-level connection.</p><table tabindex="0"><thead><tr><th>Library</th><th>Language</th><th>URL</th><th>Notes</th></tr></thead><tbody><tr><td><strong>eventsource</strong></td><td>TypeScript</td><td><a href="https://github.com/EventSource/eventsource" target="_blank" rel="noreferrer">github.com/EventSource/eventsource</a></td><td>W3C-compliant SSE client for Node.js. Auto-reconnection, custom <code>fetch</code> support.</td></tr><tr><td><strong>@microsoft/fetch-event-source</strong></td><td>TypeScript</td><td><a href="https://github.com/Azure/fetch-event-source" target="_blank" rel="noreferrer">github.com/Azure/fetch-event-source</a></td><td>Fetch-based SSE supporting POST + custom headers — required for LLM APIs (native EventSource is GET-only).</td></tr><tr><td><strong>httpx-sse</strong></td><td>Python</td><td><a href="https://pypi.org/project/httpx-sse/" target="_blank" rel="noreferrer">pypi.org/project/httpx-sse</a></td><td>SSE support for httpx (used internally by OpenAI/Anthropic SDKs).</td></tr><tr><td><strong>r3labs/sse</strong></td><td>Go</td><td><a href="https://github.com/r3labs/sse" target="_blank" rel="noreferrer">github.com/r3labs/sse</a></td><td>SSE server and client for Go.</td></tr><tr><td><strong>reqwest</strong></td><td>Rust</td><td>(built-in)</td><td>Rust typically parses SSE manually from chunked HTTP responses via reqwest/hyper.</td></tr></tbody></table><p>SSE dominates because LLM inference is inherently unidirectional (model → client). WebSocket is only used for bidirectional use cases like OpenAI&#39;s Realtime audio API.</p><h3 id="incremental-parsing" tabindex="-1">Incremental Parsing <a class="header-anchor" href="#incremental-parsing" aria-label="Permalink to &quot;Incremental Parsing&quot;">​</a></h3><p>Streaming LLM responses require parsing incomplete data — partial JSON from tool calls and token-by-token text.</p><ul><li><strong>Jiter</strong> — Fast iterable JSON parser in Rust with Python bindings. 4-10x faster than serde_json. Iterator mode processes key-value pairs as they arrive without waiting for complete JSON. <a href="https://github.com/pydantic/jiter" target="_blank" rel="noreferrer">github.com/pydantic/jiter</a>. Used by Pydantic V2 (which underlies OpenAI SDK, Anthropic SDK, and LiteLLM).</li><li><strong>@streamparser/json</strong> — SAX/pull-based streaming JSON parser for TypeScript. Handles incomplete JSON fragments from streaming tool calls. <a href="https://www.npmjs.com/package/@streamparser/json" target="_blank" rel="noreferrer">npmjs.com/package/@streamparser/json</a>.</li><li><strong>partial-json-parser</strong> — TypeScript library that parses incomplete JSON strings. Useful for showing partial tool parameters during streaming.</li><li><strong>encoding/json.Decoder</strong> — Go&#39;s built-in streaming JSON decoder. Reads tokens from an <code>io.Reader</code> without buffering the entire response.</li></ul><table tabindex="0"><thead><tr><th>Language</th><th>Recommended Parser</th><th>Approach</th></tr></thead><tbody><tr><td><strong>Rust</strong></td><td>Jiter</td><td>Iterator-based, zero-copy</td></tr><tr><td><strong>Python</strong></td><td>Pydantic partial parsing</td><td>Type-coerced validation of partial JSON</td></tr><tr><td><strong>TypeScript</strong></td><td>@streamparser/json</td><td>SAX-like streaming events</td></tr><tr><td><strong>Go</strong></td><td>encoding/json.Decoder</td><td>Built-in token-level streaming</td></tr></tbody></table><h3 id="terminal-markdown-renderers" tabindex="-1">Terminal Markdown Renderers <a class="header-anchor" href="#terminal-markdown-renderers" aria-label="Permalink to &quot;Terminal Markdown Renderers&quot;">​</a></h3><p>Render LLM markdown output with syntax highlighting, tables, and formatting in the terminal.</p><ul><li><strong>Glamour</strong> — Stylesheet-based terminal markdown renderer for Go. Multiple themes (dark, light, custom). <a href="https://github.com/charmbracelet/glamour" target="_blank" rel="noreferrer">github.com/charmbracelet/glamour</a>. Used by GitHub CLI, GitLab CLI, Glow. The standard for Go coding agents alongside Bubble Tea.</li><li><strong>Termimad</strong> — Skinnable markdown renderer for Rust with template support (<code>\${placeholder}</code> syntax). <a href="https://github.com/Canop/termimad" target="_blank" rel="noreferrer">github.com/Canop/termimad</a>. Supports tables, code blocks, scrollable views. The go-to for Rust coding agents.</li><li><strong>Rich Markdown</strong> — Part of Rich (Python). Renders markdown with syntax highlighting and integrates with <code>Live</code> display for streaming. <a href="https://github.com/Textualize/rich" target="_blank" rel="noreferrer">github.com/Textualize/rich</a>. Zero extra dependencies for Python agents.</li><li><strong>marked-terminal</strong> — Custom renderer for <code>marked</code> that outputs ANSI-styled text. <a href="https://github.com/mikaelbr/marked-terminal" target="_blank" rel="noreferrer">github.com/mikaelbr/marked-terminal</a>. Used by some Node.js coding agents.</li></ul><h3 id="spinner-progress-libraries" tabindex="-1">Spinner &amp; Progress Libraries <a class="header-anchor" href="#spinner-progress-libraries" aria-label="Permalink to &quot;Spinner &amp; Progress Libraries&quot;">​</a></h3><p>Visual feedback during LLM inference latency (before tokens start streaming) and multi-step agent workflows.</p><table tabindex="0"><thead><tr><th>Library</th><th>Language</th><th>URL</th><th>Key Feature</th></tr></thead><tbody><tr><td><strong>ora</strong></td><td>JavaScript</td><td><a href="https://github.com/sindresorhus/ora" target="_blank" rel="noreferrer">github.com/sindresorhus/ora</a></td><td>Elegant spinner with <code>.start()</code> / <code>.succeed()</code> / <code>.fail()</code> states. Pairs with Ink.</td></tr><tr><td><strong>listr2</strong></td><td>TypeScript</td><td><a href="https://github.com/listr2/listr2" target="_blank" rel="noreferrer">github.com/listr2/listr2</a></td><td>Task lists with concurrent/sequential execution and progress reporting.</td></tr><tr><td><strong>indicatif</strong></td><td>Rust</td><td><a href="https://github.com/console-rs/indicatif" target="_blank" rel="noreferrer">github.com/console-rs/indicatif</a></td><td>Progress bars + spinners with multi-progress support. Integrates with <code>tracing</code> via tracing-indicatif.</td></tr><tr><td><strong>Rich Progress</strong></td><td>Python</td><td><a href="https://github.com/Textualize/rich" target="_blank" rel="noreferrer">github.com/Textualize/rich</a></td><td><code>console.status(&quot;Thinking...&quot;)</code> for spinners; <code>Progress()</code> for multi-step tracking. Built into Rich.</td></tr><tr><td><strong>cli-spinners</strong></td><td>JavaScript</td><td><a href="https://github.com/sindresorhus/cli-spinners" target="_blank" rel="noreferrer">github.com/sindresorhus/cli-spinners</a></td><td>Collection of 80+ spinner animations as JSON data. Used by ora.</td></tr></tbody></table><hr><h2 id="real-world-implementations" tabindex="-1">Real-World Implementations <a class="header-anchor" href="#real-world-implementations" aria-label="Permalink to &quot;Real-World Implementations&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Agent</th><th>Protocol</th><th>Parsing</th><th>Rendering</th><th>Error Recovery</th><th>Reference</th></tr></thead><tbody><tr><td><strong>OpenCode</strong></td><td>SSE → Go channels</td><td>Delta events → SQLite → pub/sub</td><td>Bubble Tea + Lip Gloss</td><td>8 retries; context cancellation cascade</td><td><a href="./../agents/opencode/architecture.html"><code>../agents/opencode/architecture.md</code></a></td></tr><tr><td><strong>Claude Code</strong></td><td>SSE (Anthropic Messages API)</td><td>Content block start/delta/stop</td><td>Ink (React for CLI)</td><td>Checkpoint snapshots; rewind menu</td><td><a href="./../agents/claude-code/architecture.html"><code>../agents/claude-code/architecture.md</code></a></td></tr><tr><td><strong>Warp</strong></td><td>N/A (terminal-native)</td><td>Block metadata + PTY buffer</td><td>Rust + Metal GPU (~1.9ms redraws)</td><td>Active AI proactive error detection</td><td><a href="./../agents/warp/architecture.html"><code>../agents/warp/architecture.md</code></a></td></tr><tr><td><strong>Codex</strong></td><td>SSE + WebSocket (Responses API)</td><td>ItemCreated/Updated/Completed → SQ/EQ</td><td>Ratatui TUI + exec JSONL mode</td><td>5 stream retries; 300s idle timeout</td><td><a href="./../agents/codex/architecture.html"><code>../agents/codex/architecture.md</code></a></td></tr><tr><td><strong>Goose</strong></td><td>Async stream (<code>BoxStream&lt;AgentEvent&gt;</code>)</td><td>Stream chunks → categorize_tools()</td><td>Event-driven progressive UI</td><td>2 compaction attempts; CancellationToken</td><td><a href="./../agents/goose/agentic-loop.html"><code>../agents/goose/agentic-loop.md</code></a></td></tr><tr><td><strong>Gemini CLI</strong></td><td>SSE (<code>client.ts</code>)</td><td>contentGenerator.ts pipeline</td><td>Ink + headless modes (text/JSON/stream-json)</td><td>Retry + fallback module</td><td><a href="./../agents/gemini-cli/architecture.html"><code>../agents/gemini-cli/architecture.md</code></a></td></tr><tr><td><strong>Aider</strong></td><td>litellm (provider-agnostic)</td><td>Edit format parsers (diff/whole/udiff)</td><td>prompt_toolkit (full response)</td><td>Git-based undo; model-specific routing</td><td><a href="./../agents/aider/architecture.html"><code>../agents/aider/architecture.md</code></a></td></tr><tr><td><strong>Pi</strong></td><td>Provider-specific</td><td>Event streaming API</td><td>Custom pi-tui (differential rendering)</td><td>Extension-based recovery</td><td><a href="./../agents/pi-coding-agent/architecture.html"><code>../agents/pi-coding-agent/architecture.md</code></a></td></tr><tr><td><strong>Ante</strong></td><td>HTTP streaming (Rust)</td><td><code>fn stream() → TokenStream</code></td><td>Rust native terminal rendering</td><td>Lock-free scheduler; sub-agent isolation</td><td><a href="./../agents/ante/architecture.html"><code>../agents/ante/architecture.md</code></a></td></tr><tr><td><strong>OpenHands</strong></td><td>WebSocket/REST → EventStream</td><td>Append-only event bus with subscribers</td><td>Web UI (EventStream subscriber)</td><td>ReplayManager; full state reconstruction</td><td><a href="./../agents/openhands/architecture.html"><code>../agents/openhands/architecture.md</code></a></td></tr></tbody></table>`,157)])])}const u=t(a,[["render",s]]);export{g as __pageData,u as default};
